from haystack import Pipeline
from haystack.components.classifiers import ZeroShotTextClassifier
from haystack.utils import ComponentDevice

intent_pipeline = Pipeline()
intent_pipeline.add_component(
    "classifier",
    ZeroShotTextClassifier(model="microsoft/deberta-v3-base", device=ComponentDevice.from_str("cuda"))
)

intent_pipeline.add_edge(
    "classifier.candidate_labels",
    "classifier.labels",
    inputs=["reply", "forward", "archive", "draft"]
)

result = intent_pipeline.run({
    "classifier": {
        "text": "Please review the attached Q3 financials and provide feedback by EOD"
    }
})
print(result["classifier"]["labels"][0])  # 'reply'

from haystack import component

@component
class AttachmentProcessor:
    @component.output_types(attachments=dict, safe_to_forward=bool)
    def run(self, email_content: str, max_size_mb: int = 10):
        import email.mime.multipart
from email import policy
        msg = email.message_from_string(email_content, policy=policy.default)
        attachments = {}
        safe = True

        for part in msg.walk():
            if part.get_content_maintype() == 'multipart':
                continue
            if part.get('Content-Disposition') is None:
                continue
            filename = part.get_filename()
            if filename:
                size = len(part.get_payload(decode=True))
                if size > max_size_mb * 1024 * 1024:
                    safe = False
                attachments[filename] = size

        return {"attachments": attachments, "safe_to_forward": safe}

