from haystack import component
import vex

@component
class VexPIIFilter:
    def __init__(self):
        self.vex_client = vex.Client(api_key="your-vex-key")

    @component.output_types(clean_text=str, pii_detected=list, safe_to_send=bool)
    def run(self, text: str):
        verification = self.vex_client.verify(
            text,
            checks=[
                vex.PIIFilterCheck(),
                vex.ConfidenceCheck(min_score=0.9)
            ]
        )

        return {
            "clean_text": verification.cleaned_output,
            "pii_detected": verification.issues,
            "safe_to_send": verification.passed
        }

# Usage in pipeline
pipeline.add_component("pii_filter", VexPIIFilter())
pipeline.connect("generator", "pii_filter.text")

from haystack import component
import vex

@component
class VexToneGuardrail:
    def __init__(self):
        self.vex_client = vex.Client(api_key="your-vex-key")

    @component.output_types(tone_score=float, professional=bool, suggestions=list)
    def run(self, draft: str):
        result = self.vex_client.verify(
            draft,
            checks=[
                vex.SentimentCheck(desired_sentiment="neutral-positive"),
                vex.CustomCheck(
                    name="professionalism",
                    prompt="Rate professional tone 0-1 for corporate email"
                )
            ]
        )

        return {
            "tone_score": result.metrics["professionalism"],
            "professional": result.metrics["professionalism"] > 0.85,
            "suggestions": result.suggestions
        }

from haystack import component
import vex

@component
class VexFaithfulnessCheck:
    def __init__(self):
        self.vex_client = vex.Client(api_key="your-vex-key")

    @component.output_types(faithful=bool, hallucination_score=float, evidence_used=str)
    def run(self, context: list, generated_reply: str):
        context_text = "\n".join([doc.content for doc in context])

        verification = self.vex_client.verify(
            generated_reply,
            context=[context_text],
            checks=[
                vex.GroundingCheck(),
                vex.HallucinationCheck(threshold=0.1)
            ]
        )

        return {
            "faithful": verification.passed,
            "hallucination_score": verification.metrics["hallucination"],
            "evidence_used": verification.evidence
        }

# Pipeline connection
pipeline.connect("retriever.documents", "faithfulness.context")
pipeline.connect("generator.replies", "faithfulness.generated_reply")
